// Function to remove an item from an array
function removeItem(arr, item) {
  // Find index of item in array
  let idx = arr.findIndex(x => x === item);

  // If item is found, remove it from array
  if (idx !== -1) {
    arr.splice(idx, 1);
  }

  return arr;
}

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5)+1):
        if n % i == 0:
            return False
    return True

